import unittest
from bench_public import FirmwareSession, self_test_artifact_dir


class ControllerSmokeTest(unittest.TestCase):
    """Basic smoke test for controller behavior."""

    def setUp(self):
        self.artifact_dir = self_test_artifact_dir("smoke")
        self.session = None

    def tearDown(self):
        if self.session:
            self.session.close()

    def test_boot_and_first_actuator_response(self) -> None:
        """Test that boot leaves compressor off and vent open."""
        artifact_dir = self_test_artifact_dir("smoke")
        with FirmwareSession(artifact_dir=artifact_dir, port=5555) as session:
            session.wait_for_boot(timeout_s=2.0)
            lines = session.read_lines(timeout_s=0.1)
            # Should start in SAFE_VENT state with compressor off and vent open
            self.assertTrue(len(lines) > 0, "Expected boot to send actuator commands")
            for line in lines:
                if line.startswith("ACT COMPRESSOR OFF"):
