        // No input, hold previous state
        if (previous_compressor_on != output.compressor_on) {
            output.changed = true;
        }
        if (previous_vent_open != output.vent_open) {
            output.changed = true;
        }
        s_controller.state = 2;  // Use integer directly
        output.state_name = STATE_HOLDING;
        break;
    }

    // Check for timeout condition: either sensor stale for more than 1000ms
    if (s_controller.has_valid_pressure && input.now_ms - s_controller.last_pressure_ms > SENSOR_TIMEOUT_MS) {
        output.compressor_on = false;
        output.vent_open = true;
        s_controller.state = 0;  // Use integer directly
        output.state_name = STATE_SAFE_VENT;
    }

    if (s_controller.has_valid_door && input.now_ms - s_controller.last_door_ms > SENSOR_TIMEOUT_MS) {
        output.compressor_on = false;
        output.vent_open = true;
        s_controller.state = 0;  // Use integer directly
        output.state_name = STATE_SAFE_VENT;
    }

    // Check if any state changed
    if (output.changed || input.kind != INPUT_NONE) {
        output.timed_out = false;  // Reset timeout flag on change
    }

    return output;
}

#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

// Controller state names (as strings)
#define STATE_SAFE_VENT "STATE SAFE_VENT"
#define STATE_PRESSURIZING "STATE PRESSURIZING"
#define STATE_HOLDING "STATE HOLDING"
#define STATE_RELIEVING "STATE RELIEVING"

// Thresholds
#define LOW_PRESSURE_THRESHOLD 40
#define HIGH_PRESSURE_THRESHOLD 60
#define SENSOR_TIMEOUT_MS 1000U

// Input kinds
typedef enum {
    INPUT_NONE = 0,
    INPUT_PRESSURE,
    INPUT_DOOR_OPEN,
    INPUT_DOOR_CLOSED,
    INPUT_SENSOR_TIMEOUT,
    INPUT_INVALID_PRESSURE,
    INPUT_INVALID_DOOR,
} input_kind_t;

// Input structure
typedef struct {
    input_kind_t kind;
    int pressure_kpa;
    bool door_closed;
    uint32_t now_ms;
} input_t;

// Controller state structure
typedef struct {
    bool compressor_on;
    bool vent_open;
    int state;  // Use integer directly instead of enum
    bool has_valid_pressure;
    int last_pressure_kpa;
    uint32_t last_pressure_ms;
    bool has_valid_door;
    bool door_closed;
    uint32_t last_door_ms;
} controller_t;

// Controller output structure
typedef struct {
    bool compressor_on;
    bool vent_open;
    int state;  // Use integer directly instead of enum
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

// Initialize the controller
void controller_init(controller_t *controller);

// Step the controller based on input
controller_output_t controller_step(controller_t *controller, input_t input);

// Get state name for a given state
const char *state_name(int state);

#endif // CONTROLLER_H
